import React, { useState, useEffect } from 'react';
import {
  ShoppingCart,
  DollarSign,
  TrendingUp,
  Clock,
  Loader,
  AlertCircle,
  CreditCard,
  Package,
} from 'lucide-react';
import api from '../../services/api';

const StatCard = ({ icon: Icon, title, value, subtitle, color = 'blue' }) => {
  const colorClasses = {
    blue: 'from-blue-400 to-blue-600',
    green: 'from-green-400 to-green-600',
    purple: 'from-purple-400 to-purple-600',
    orange: 'from-orange-400 to-orange-600',
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 hover:shadow-md transition-shadow">
      <div className="flex items-start justify-between">
        <div>
          <p className="text-gray-600 text-sm font-medium">{title}</p>
          <h3 className="text-3xl font-bold text-gray-900 mt-2">{value}</h3>
          {subtitle && <p className="text-xs text-gray-500 mt-1">{subtitle}</p>}
        </div>
        <div className={`w-12 h-12 rounded-lg bg-gradient-to-br ${colorClasses[color]} flex items-center justify-center`}>
          <Icon className="w-6 h-6 text-white" />
        </div>
      </div>
    </div>
  );
};

const StaffDashboard = () => {
  const [stats, setStats] = useState({
    todaysSales: 0,
    salesCount: 0,
    totalCash: 0,
    avgSaleValue: 0,
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [recentTransactions, setRecentTransactions] = useState([]);

  useEffect(() => {
    fetchStaffData();
  }, []);

  const fetchStaffData = async () => {
    setLoading(true);
    setError('');
    try {
      const response = await api.get('/sales') || { data: [] };
      const salesData = response.data || [];

      // Get today's sales
      const today = new Date().toDateString();
      const todaysSales = salesData.filter(
        sale => new Date(sale.saleDate).toDateString() === today
      );

      const todayTotal = todaysSales.reduce((sum, sale) => sum + (sale.totalAmount || 0), 0);
      const avgValue = todaysSales.length > 0 ? todayTotal / todaysSales.length : 0;

      setStats({
        todaysSales: todayTotal,
        salesCount: todaysSales.length,
        totalCash: todayTotal,
        avgSaleValue: avgValue,
      });

      setRecentTransactions(todaysSales.slice(0, 5));
    } catch (err) {
      console.error('Error fetching staff data:', err);
      setError('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader className="w-8 h-8 text-blue-500 animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Welcome Section */}
      <div className="bg-gradient-to-r from-green-600 to-emerald-600 rounded-xl p-6 text-white shadow-lg">
        <h1 className="text-3xl font-bold mb-2">Welcome back! 👋</h1>
        <p className="text-green-100">Your point-of-sale dashboard for today's transactions</p>
      </div>

      {/* Today's Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard
          icon={DollarSign}
          title="Today's Sales"
          value={`$${stats.todaysSales.toFixed(2)}`}
          subtitle="Total revenue"
          color="green"
        />
        <StatCard
          icon={ShoppingCart}
          title="Total Transactions"
          value={stats.salesCount}
          subtitle="Completed sales"
          color="blue"
        />
        <StatCard
          icon={CreditCard}
          title="Avg Sale Value"
          value={`$${stats.avgSaleValue.toFixed(2)}`}
          subtitle="Per transaction"
          color="purple"
        />
        <StatCard
          icon={TrendingUp}
          title="Cash Collected"
          value={`$${stats.totalCash.toFixed(2)}`}
          subtitle="Ready for deposit"
          color="orange"
        />
      </div>

      {/* Main Content Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Recent Transactions */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200">
          <div className="p-6 border-b border-gray-200">
            <h2 className="text-lg font-bold text-gray-900">Today's Transactions</h2>
          </div>
          <div className="p-6">
            {error && (
              <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
                <AlertCircle className="w-5 h-5 text-red-500 flex-shrink-0 mt-0.5" />
                <p className="text-red-700 text-sm">{error}</p>
              </div>
            )}
            {recentTransactions.length === 0 ? (
              <div className="text-center py-12">
                <ShoppingCart className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                <p className="text-gray-500">No transactions yet today</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-gray-200">
                      <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                        Time
                      </th>
                      <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                        Customer
                      </th>
                      <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                        Items
                      </th>
                      <th className="px-4 py-3 text-right text-xs font-semibold text-gray-700 uppercase tracking-wider">
                        Amount
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {recentTransactions.map((transaction, index) => (
                      <tr
                        key={index}
                        className="border-b border-gray-100 hover:bg-gray-50 transition-colors"
                      >
                        <td className="px-4 py-3 text-sm text-gray-600">
                          {new Date(transaction.saleDate).toLocaleTimeString()}
                        </td>
                        <td className="px-4 py-3 text-sm font-medium text-gray-900">
                          {transaction.customerName || 'Walk-in'}
                        </td>
                        <td className="px-4 py-3 text-sm text-gray-600">
                          {(transaction.saleDetails?.length || 0)} items
                        </td>
                        <td className="px-4 py-3 text-sm font-semibold text-gray-900 text-right">
                          ${(transaction.totalAmount || 0).toFixed(2)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>

        {/* Quick Actions & Info */}
        <div className="space-y-6">
          {/* Quick Actions */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <h2 className="text-lg font-bold text-gray-900 mb-6">Quick Actions</h2>
            <div className="space-y-3">
              <button className="w-full px-4 py-3 bg-blue-50 hover:bg-blue-100 text-blue-700 font-medium rounded-lg transition-colors">
                <div className="flex items-center gap-2">
                  <ShoppingCart className="w-4 h-4" />
                  New Sale
                </div>
              </button>
              <button className="w-full px-4 py-3 bg-green-50 hover:bg-green-100 text-green-700 font-medium rounded-lg transition-colors">
                <div className="flex items-center gap-2">
                  <Package className="w-4 h-4" />
                  Check Stock
                </div>
              </button>
              <button className="w-full px-4 py-3 bg-purple-50 hover:bg-purple-100 text-purple-700 font-medium rounded-lg transition-colors">
                <div className="flex items-center gap-2">
                  <Clock className="w-4 h-4" />
                  View Reports
                </div>
              </button>
            </div>
          </div>

          {/* Shift Info */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <h2 className="text-lg font-bold text-gray-900 mb-4">Shift Info</h2>
            <div className="space-y-3">
              <div className="flex items-center justify-between p-3 bg-blue-50 rounded-lg">
                <span className="text-sm text-gray-700">Shift Status</span>
                <span className="font-bold text-blue-600">Active</span>
              </div>
              <div className="flex items-center justify-between p-3 bg-green-50 rounded-lg">
                <span className="text-sm text-gray-700">Start Time</span>
                <span className="font-bold text-green-600">
                  {new Date().toLocaleTimeString([], {
                    hour: '2-digit',
                    minute: '2-digit',
                  })}
                </span>
              </div>
              <div className="flex items-center justify-between p-3 bg-orange-50 rounded-lg">
                <span className="text-sm text-gray-700">Till Balance</span>
                <span className="font-bold text-orange-600">$0.00</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Refresh Button */}
      <button
        onClick={fetchStaffData}
        disabled={loading}
        className="inline-flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors disabled:opacity-50"
      >
        {loading ? <Loader className="w-4 h-4 animate-spin" /> : null}
        Refresh Dashboard
      </button>
    </div>
  );
};

export default StaffDashboard;
